// Summary: Tests Map region rendering, nested data attribute, overlay and control toggles, and rail tile semantics.

import '@testing-library/jest-dom';
import * as React from 'react';
import { render, screen } from '@testing-library/react';
import { Map, type MapProps } from './Map';

const renderMap = (props?: Partial<MapProps>) => {
  return render(
    <Map ariaLabel="Delivery area" {...props}>
      <span>Map content</span>
    </Map>
  );
};

describe('Map', () => {
  it('renders a region with the provided ariaLabel', () => {
    renderMap();
    expect(screen.getByRole('region', { name: 'Delivery area' })).toBeInTheDocument();
  });

  it('omits the data-is-nested attribute by default', () => {
    const { container } = renderMap();
    const root = container.querySelector('section');
    const attributeAbsent = root !== null && !root.hasAttribute('data-is-nested');
    expect(attributeAbsent).toBe(true);
  });

  it('applies data-is-nested="true" when isNested is provided', () => {
    const { container } = renderMap({ isNested: true });
    const root = container.querySelector('section');
    const attributeValue = root?.getAttribute('data-is-nested');
    expect(attributeValue).toBe('true');
  });

  it('omits the overlay when showOverlay is false', () => {
    const { container } = renderMap({ showOverlay: false });
    const overlay = container.querySelector('[data-part="overlay"]');
    expect(overlay).toBeNull();
  });

  it('omits the control rail when showControls is false', () => {
    const { container } = renderMap({ showControls: false });
    const rail = container.querySelector('[data-part="rail"]');
    expect(rail).toBeNull();
  });

  it('renders three disabled control tiles with stable hooks and labels', () => {
    const { container } = renderMap();
    const tiles = Array.from(container.querySelectorAll('[data-part="tile"]')) as HTMLButtonElement[];
    const icons = Array.from(container.querySelectorAll('[data-part="icon"]'));
    const actions = tiles.map(tile => tile.getAttribute('data-action'));
    const labels = tiles.map(tile => tile.getAttribute('aria-label'));
    const hasValidTiles =
      tiles.length === 3 &&
      tiles.every(tile => tile.tagName === 'BUTTON' && tile.type === 'button' && tile.disabled);
    const actionsMatch =
      JSON.stringify(actions) === JSON.stringify(['zoomIn', 'zoomOut', 'nearMe']);
    const labelsMatch =
      JSON.stringify(labels) === JSON.stringify(['Zoom in', 'Zoom out', 'Near me']);
    const iconsHidden =
      icons.length === 3 && icons.every(icon => icon.getAttribute('aria-hidden') === 'true');
    expect(hasValidTiles && actionsMatch && labelsMatch && iconsHidden).toBe(true);
  });
});

